WITH inventory_start AS (
  SELECT sku_id, SUM(quantity) AS beginning_inventory FROM inventory_snapshots WHERE snapshot_date = {start_date} GROUP BY sku_id
),
units_sold AS (
  SELECT oi.product_id AS sku_id, SUM(oi.quantity) AS units_sold FROM order_items oi JOIN orders o ON oi.order_id = o.order_id WHERE o.status = 'completed' AND o.order_date BETWEEN {start_date} AND {end_date} GROUP BY oi.product_id
),
inventory_end AS (
  SELECT oi.product_id AS sku_id, SUM(oi.quantity) AS ending_inventory FROM inventory_snapshots WHERE snapshot_date = {end_date} GROUP BY oi.product_id
)
SELECT s.sku_id, COALESCE(s.beginning_inventory, 0) AS beginning, COALESCE(u.units_sold, 0) AS sold, COALESCE(e.ending_inventory, 0) AS ending, COALESCE(u.units_sold, 0) * 100.0 / NULLIF(s.beginning_inventory, 0) AS sell_through_rate FROM inventory_start s LEFT JOIN units_sold u ON s.sku_id = u.sku_id LEFT JOIN inventory_end e ON s.sku_id = e.sku_id

WITH active_skus AS (
  SELECT DISTINCT sku_id FROM inventory_snapshots WHERE snapshot_date = {end_date} AND quantity > 0
),
recent_sales AS (
  SELECT DISTINCT oi.product_id AS sku_id FROM order_items oi JOIN orders o ON oi.order_id = o.order_id WHERE o.status = 'completed' AND o.order_date >= DATEADD(day, -90, {end_date})
),
inventory_counts AS (
  SELECT COUNT(DISTINCT a.sku_id) AS active_count FROM active_skus a
),
dead_counts AS (
  SELECT COUNT(DISTINCT a.sku_id) AS dead_count FROM active_skus a LEFT JOIN recent_sales r ON a.sku_id = r.sku_id WHERE r.sku_id IS NULL
)
SELECT dc.dead_count, ic.active_count, dc.dead_count * 100.0 / NULLIF(ic.active_count, 0) AS dead_stock_rate FROM dead_counts dc, inventory_counts ic

WITH inventory_on_hand AS (
  SELECT sku_id, SUM(quantity) AS on_hand FROM inventory_snapshots WHERE snapshot_date = {end_date} GROUP BY sku_id
),
forward_demand AS (
  SELECT oi.product_id AS sku_id, SUM(oi.quantity) * 3 AS demand_90d FROM order_items oi JOIN orders o ON oi.order_id = o.order_id WHERE o.status = 'completed' AND o.order_date >= DATEADD(day, -30, {end_date}) GROUP BY oi.product_id
),
overstock AS (
  SELECT i.sku_id, COALESCE(i.on_hand, 0) AS on_hand, COALESCE(d.demand_90d, 0) AS demand, COALESCE(i.on_hand, 0) / NULLIF(d.demand_90d, 0) AS overstock_index FROM inventory_on_hand i LEFT JOIN forward_demand d ON i.sku_id = d.sku_id
)
SELECT COUNT(DISTINCT CASE WHEN overstock_index > 1 THEN sku_id END) AS overstock_skus, COUNT(DISTINCT sku_id) AS total_skus, COUNT(DISTINCT CASE WHEN overstock_index > 1 THEN sku_id END) * 100.0 / NULLIF(COUNT(DISTINCT sku_id), 0) AS overstock_index_pct, AVG(overstock_index) AS avg_overstock_index FROM overstock

WITH new_products AS (
  SELECT product_id, MIN(order_date) AS launch_date FROM order_items oi JOIN orders o ON oi.order_id = o.order_id GROUP BY product_id HAVING MIN(order_date) >= DATEADD(day, -90, {end_date})
),
new_product_revenue AS (
  SELECT SUM(nr.net_revenue) AS new_product_revenue FROM order_items oi JOIN new_products np ON oi.product_id = np.product_id JOIN net_revenue_daily nr ON oi.order_id = nr.order_id
),
total_revenue AS (
  SELECT SUM(net_revenue) AS total_revenue FROM net_revenue_daily nr WHERE order_date BETWEEN {start_date} AND {end_date}
)
SELECT COALESCE(npr.new_product_revenue, 0) AS new_product_revenue, tr.total_revenue, COALESCE(npr.new_product_revenue, 0) * 100.0 / NULLIF(tr.total_revenue, 0) AS new_product_revenue_share FROM new_product_revenue npr, total_revenue tr
